import re

# Load books data
with open('var_functions.query_db:46.json', 'r') as f:
    books = json.load(f)

# Load reviews data
with open('var_functions.query_db:40.json', 'r') as f:
    reviews = json.load(f)

print("Books loaded:", len(books))
print("Reviews loaded:", len(reviews))

# Extract publication years from books
book_decades = {}
year_pattern = re.compile(r'\b(19\d{2}|20[01]\d|202[0-3])\b')

# Parse reviews to get book ratings
book_ratings = {}
for review in reviews:
    purchase_id = review['purchase_id']  # e.g., "purchaseid_186"
    rating = float(review['rating'])

    book_id = None
    # Try to extract numeric part from purchase_id
    match = re.search(r'purchaseid_(\d+)', purchase_id)
    if match:
        numeric_id = match.group(1)
        book_id = f'bookid_{numeric_id}'

    if book_id:
        if book_id not in book_ratings:
            book_ratings[book_id] = []
        book_ratings[book_id].append(rating)

print("Books with reviews:", len(book_ratings))

# Extract publication years
books_with_years = 0
for book in books:
    book_id = book['book_id']
    details = book['details']

    # Find all 4-digit years
    years = year_pattern.findall(details)
    if years:
        years_int = [int(y) for y in years]
        valid_years = [y for y in years_int if 1900 <= y <= 2023]

        if valid_years:
            # Get the year from a date pattern if possible
            date_match = re.search(r'(?:published|released) on (?:January|February|March|April|May|June|July|August|September|October|November|December)[^,]*,? (\d{4})', details, re.IGNORECASE)
            if date_match:
                pub_year = int(date_match.group(1))
            else:
                # Use the first valid year found
                pub_year = valid_years[0]

            decade = (pub_year // 10) * 10
            book_decades[book_id] = {
                'decade': decade,
                'year': pub_year
            }
            books_with_years += 1

print("Books with publication years:", books_with_years)
print("Books with both year and reviews:", len(set(book_decades.keys()) & set(book_ratings.keys())))

# Calculate decade averages
decade_stats = {}
for book_id, ratings in book_ratings.items():
    if book_id in book_decades:
        decade = book_decades[book_id]['decade']

        if decade not in decade_stats:
            decade_stats[decade] = {
                'total_ratings': 0,
                'sum_ratings': 0,
                'book_ids': set()
            }

        decade_stats[decade]['total_ratings'] += len(ratings)
        decade_stats[decade]['sum_ratings'] += sum(ratings)
        decade_stats[decade]['book_ids'].add(book_id)

print("\nDecades with books that have reviews:", len(decade_stats))

# Filter decades with at least 10 distinct books and calculate averages
decade_averages = {}
for decade, stats in decade_stats.items():
    distinct_books = len(stats['book_ids'])
    if distinct_books >= 10:
        avg_rating = stats['sum_ratings'] / stats['total_ratings']
        decade_averages[decade] = {
            'avg_rating': avg_rating,
            'distinct_books': distinct_books,
            'total_ratings': stats['total_ratings']
        }

print("Decades with >=10 books:", len(decade_averages))

# Sort by average rating
sorted_decades = sorted(decade_averages.items(), key=lambda x: x[1]['avg_rating'], reverse=True)

print("\nTop decades by average rating:")
for decade, data in sorted_decades[:10]:
    print(f"{decade}s: avg rating = {data['avg_rating']:.3f}, distinct books = {data['distinct_books']}, total ratings = {data['total_ratings']}")

if sorted_decades:
    top_decade = sorted_decades[0]
    result = {
        "decade": top_decade[0],
        "avg_rating": round(top_decade[1]['avg_rating'], 3),
        "distinct_books": top_decade[1]['distinct_books'],
        "total_ratings": top_decade[1]['total_ratings']
    }
else:
    result = {"error": "No decades found with 10+ books"}

print("\n__RESULT__:")
print(json.dumps(result))"}

